const wf02 = $('WF-CRM-02 상태 조회').first().json || {};
const wf01 = $('WF-CRM-01 상태 조회').first().json || {};
const static02 = wf02.staticData?.global || {};
const static01 = wf01.staticData?.global || {};
const mailLedger = Array.isArray(static02.presscoBankMailLedger) ? static02.presscoBankMailLedger : [];
const txnLedger = Array.isArray(static02.presscoBankTransactionLedger) ? static02.presscoBankTransactionLedger : [];
const failureLog = Array.isArray(static02.presscoCrmFailureLog) ? static02.presscoCrmFailureLog : [];
const reviewQueue = Array.isArray(static01.reviewQueue) ? static01.reviewQueue : [];
const staticData = $getWorkflowStaticData('global');
const sentMap = staticData.presscoBankReconAlertSent && typeof staticData.presscoBankReconAlertSent === 'object'
  ? staticData.presscoBankReconAlertSent
  : {};
if (!staticData.reconBaselineStartedAt) {
  staticData.reconBaselineStartedAt = new Date().toISOString();
}
const now = Date.now();
const pendingThresholdMs = 20 * 60 * 1000;
const recentWindowMs = 72 * 60 * 60 * 1000;
const dedupeWindowMs = 6 * 60 * 60 * 1000;
const issues = [];

function toMillis(value) {
  const date = new Date(value || 0);
  const time = date.getTime();
  return Number.isFinite(time) ? time : 0;
}

function formatDateTime(value) {
  if (!value) return '-';
  const date = new Date(value);
  if (!Number.isFinite(date.getTime())) return String(value);
  return date.toLocaleString('ko-KR', { timeZone: 'Asia/Seoul', hour12: false });
}

function toKstDate(value) {
  const date = new Date(value || 0);
  if (!Number.isFinite(date.getTime())) return 'unknown';
  return new Intl.DateTimeFormat('sv-SE', {
    timeZone: 'Asia/Seoul',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).format(date);
}

function pushIssue(key, severity, title, detail) {
  issues.push({ key, severity, title, detail });
}

const baselineAgeMs = now - toMillis(staticData.reconBaselineStartedAt);
if (baselineAgeMs > recentWindowMs && mailLedger.length === 0) {
  pushIssue('mail-ledger-empty', 'critical', '메일 ledger 비어 있음', 'WF-CRM-02 staticData에 presscoBankMailLedger가 없습니다.');
}

if (baselineAgeMs > recentWindowMs && txnLedger.length === 0) {
  pushIssue('txn-ledger-empty', 'critical', '거래 ledger 비어 있음', 'WF-CRM-02 staticData에 presscoBankTransactionLedger가 없습니다.');
}

const recentMail = mailLedger.filter((entry) => now - toMillis(entry.processedAt || entry.receivedAt) <= recentWindowMs);
const recentTx = txnLedger.filter((entry) => now - toMillis(entry.parsedAt || entry.lastUpdatedAt || entry.createdAt) <= recentWindowMs);

for (const entry of recentMail) {
  const ageMs = now - toMillis(entry.processedAt || entry.receivedAt);
  if (entry.parseFailure === true) {
    if (entry.parseAlertStatus === 'failed') {
      pushIssue(
        'parse-alert-failed::' + entry.messageKey,
        'critical',
        '파싱 실패 경보 Telegram 발송 실패',
        `${entry.subject || '-'} / ${formatDateTime(entry.processedAt || entry.receivedAt)} / ${entry.parseAlertFailureReason || 'unknown_telegram_error'}`,
      );
    } else if (entry.parseAlertStatus !== 'sent' && ageMs > pendingThresholdMs) {
      pushIssue(
        'parse-alert-pending::' + entry.messageKey,
        'critical',
        '파싱 실패 경보 미발송',
        `${entry.subject || '-'} / ${formatDateTime(entry.processedAt || entry.receivedAt)} / 사유 ${entry.parseFailureReason || '-'}`,
      );
    }
  }
}

for (const entry of recentTx) {
  const ageMs = now - toMillis(entry.parsedAt || entry.lastUpdatedAt || entry.createdAt);
  if (entry.alertStatus === 'failed') {
    pushIssue(
      'tx-alert-failed::' + entry.eventKey,
      'critical',
      '거래 알림 Telegram 발송 실패',
      `${entry.direction || 'unknown'} / ${entry.party || entry.sender || '-'} / ${(Number(entry.amount) || 0).toLocaleString()}원 / ${formatDateTime(entry.occurredAt || entry.parsedAt)} / ${entry.alertFailureReason || 'unknown_telegram_error'}`,
    );
    continue;
  }
  if (entry.alertStatus !== 'sent' && ageMs > pendingThresholdMs) {
    const label = entry.alertKind === 'crm_deposit' ? '입금 CRM 알림' : '은행 거래 알림';
    pushIssue(
      'tx-alert-pending::' + entry.eventKey,
      'critical',
      label + ' 미확정',
      `${entry.direction || 'unknown'} / ${entry.party || entry.sender || '-'} / ${(Number(entry.amount) || 0).toLocaleString()}원 / ${formatDateTime(entry.occurredAt || entry.parsedAt)} / 상태 ${entry.alertStatus || 'pending'}`,
    );
  }
}

const dayMap = new Map();
function getDay(dateKey) {
  if (!dayMap.has(dateKey)) {
    dayMap.set(dateKey, {
      nhMail: 0,
      parseFailures: 0,
      deposits: 0,
      withdrawals: 0,
      sent: 0,
      failed: 0,
      pending: 0,
    });
  }
  return dayMap.get(dateKey);
}
for (const entry of recentMail) {
  const day = toKstDate(entry.processedAt || entry.receivedAt);
  const bucket = getDay(day);
  if (entry.isNhMail) bucket.nhMail += 1;
  if (entry.parseFailure) bucket.parseFailures += 1;
}
for (const entry of recentTx) {
  const day = toKstDate(entry.occurredAt || entry.parsedAt || entry.createdAt);
  const bucket = getDay(day);
  if (entry.direction === 'deposit') bucket.deposits += 1;
  else bucket.withdrawals += 1;
  if (entry.alertStatus === 'sent') bucket.sent += 1;
  else if (entry.alertStatus === 'failed') bucket.failed += 1;
  else bucket.pending += 1;
}
for (const [day, bucket] of Array.from(dayMap.entries()).sort()) {
  if (bucket.parseFailures > 0 || bucket.failed > 0 || bucket.pending > 0) {
    pushIssue(
      'daily-mismatch::' + day,
      'high',
      `일일 정합성 주의 ${day}`,
      `NH메일 ${bucket.nhMail} / 파싱실패 ${bucket.parseFailures} / 입금 ${bucket.deposits} / 출금 ${bucket.withdrawals} / sent ${bucket.sent} / failed ${bucket.failed} / pending ${bucket.pending}`,
    );
  }
}

const recentFailureLog = failureLog.filter((entry) => now - toMillis(entry.loggedAt) <= recentWindowMs);
const telegramFailureCount = recentFailureLog.filter((entry) => entry.kind === 'telegram_failure').length;
if (telegramFailureCount > 0) {
  pushIssue(
    'telegram-failure-count::' + telegramFailureCount,
    'high',
    '최근 Telegram 실패 로그 존재',
    `최근 72시간 Telegram 실패 ${telegramFailureCount}건 / reviewQueue pending ${reviewQueue.filter((entry) => entry.status === 'review' || entry.status === 'unmatched').length}건`,
  );
}

const deliverableIssues = issues.filter((issue) => {
  const sentAt = toMillis(sentMap[issue.key]);
  return !sentAt || now - sentAt >= dedupeWindowMs;
});
if (deliverableIssues.length === 0) {
  return [];
}
for (const issue of deliverableIssues) {
  sentMap[issue.key] = new Date(now).toISOString();
}
const sentKeys = Object.keys(sentMap);
if (sentKeys.length > 500) {
  sentKeys.sort((left, right) => String(sentMap[left]).localeCompare(String(sentMap[right]))).slice(0, sentKeys.length - 500).forEach((key) => delete sentMap[key]);
}
staticData.presscoBankReconAlertSent = sentMap;

const severityIcon = (value) => value === 'critical' ? '❌' : '⚠️';
const lines = [
  '[입금 정합성 감사 경보]',
  '',
  `감지 시각: ${new Date(now).toLocaleString('ko-KR', { timeZone: 'Asia/Seoul', hour12: false })}`,
  `최근 NH 메일: ${recentMail.length}건 / 최근 거래 ledger: ${recentTx.length}건 / reviewQueue pending: ${reviewQueue.filter((entry) => entry.status === 'review' || entry.status === 'unmatched').length}건`,
  '',
];
deliverableIssues.slice(0, 12).forEach((issue) => {
  lines.push(`${severityIcon(issue.severity)} ${issue.title}`);
  lines.push(issue.detail);
  lines.push('');
});
if (deliverableIssues.length > 12) {
  lines.push(`... 외 ${deliverableIssues.length - 12}건`);
}
return [{ json: { message: lines.join('\n') } }];
